agent_output:
{
  "domain_analysis": {
    "business_context": "Evolution of a delivery platform's core domain model from a 1:1 Shipment-to-Recipient relationship to a 1:N relationship. This is a fundamental change to the aggregate root structure of the Shipment bounded context, affecting data models, partner integrations, billing, tracking, and delivery operations. The change reflects a real-world business need — e.g., split deliveries, gift shipments to multiple people from a single order, or B2B distribution scenarios.",
    "bounded_context": "Shipment / Delivery Management",
    "ubiquitous_language": [
      { "term": "Shipment", "definition": "The aggregate root representing a logistical unit of goods moving from origin to one or more destinations. Owns lifecycle (created, in-transit, delivered, failed)." },
      { "term": "Recipient", "definition": "A value object or entity representing a person or location that receives part or all of a Shipment. Has name, address, phone number, and delivery preferences." },
      { "term": "Delivery Preferences", "definition": "Recipient-level configuration governing how delivery should occur — e.g., leave at door, require signature, preferred time window, safe place instructions." },
      { "term": "Multi-Recipient Shipment", "definition": "A Shipment with more than one Recipient, where each Recipient may have distinct addresses and delivery preferences." },
      { "term": "Shipment Status", "definition": "The lifecycle state of a Shipment. In a multi-recipient model, this must account for partial completion — some Recipients delivered, others pending." },
      { "term": "Partner API", "definition": "External integrations that consume shipment data in a defined contract format. Currently expects exactly one Recipient per Shipment." }
    ]
  },

  "business_rules": [
    {
      "id": "BR-1",
      "rule": "A Shipment MUST have at least one Recipient. Zero Recipients is invalid.",
      "invariant": true,
      "invariant_justification": "A Shipment without a Recipient has no destination and cannot exist in a logistically coherent state. This is a data integrity constraint — the system is corrupt if violated.",
      "testable_assertion": "Any attempt to create or update a Shipment to have zero Recipients must be rejected with a validation error."
    },
    {
      "id": "BR-2",
      "rule": "Each Recipient MUST have a name, a valid address, and a phone number.",
      "invariant": true,
      "invariant_justification": "These are the minimum fields required for a courier to execute a delivery. Without them, the delivery is physically unperformable.",
      "testable_assertion": "Creating a Recipient with a null/empty name, address, or phone number must be rejected."
    },
    {
      "id": "BR-3",
      "rule": "Each Recipient within a Shipment owns its own delivery preferences independently.",
      "invariant": false,
      "invariant_justification": "Delivery preferences are a business policy configuration. A VP could decide to enforce uniform preferences per Shipment in the future.",
      "testable_assertion": "Two Recipients on the same Shipment can have different delivery preference values (e.g., one requires signature, the other allows safe-place delivery)."
    },
    {
      "id": "BR-4",
      "rule": "Existing single-recipient Shipments must remain valid and fully functional after migration. No data loss, no behavioral regression.",
      "invariant": true,
      "invariant_justification": "2 million production records depend on the current model. Data corruption or loss during migration would violate system integrity and contractual obligations.",
      "testable_assertion": "After migration, every existing Shipment has exactly one Recipient with name, address, and phone matching pre-migration values. All existing API calls and queries return equivalent results."
    },
    {
      "id": "BR-5",
      "rule": "Shipment status must coherently represent the aggregate delivery state across all Recipients.",
      "invariant": true,
      "invariant_justification": "A Shipment marked 'delivered' while one Recipient has not received their delivery is a state integrity violation — it misrepresents physical reality.",
      "testable_assertion": "A Shipment with 3 Recipients where 2 are delivered and 1 is pending must NOT have a top-level status of 'delivered'. It must reflect partial completion (e.g., 'partially_delivered' or equivalent)."
    },
    {
      "id": "BR-6",
      "rule": "Partner APIs must continue to receive shipment data in a format they can consume. Breaking changes require versioning or an anti-corruption layer.",
      "invariant": true,
      "invariant_justification": "Silently changing the API contract would corrupt partner integrations, potentially causing delivery failures, lost revenue, and SLA breaches.",
      "testable_assertion": "Existing partner API endpoints return the same response schema for single-recipient Shipments as they did before migration. Multi-recipient data is either excluded or delivered via a new API version."
    },
    {
      "id": "BR-7",
      "rule": "A Recipient cannot appear more than once within the same Shipment (uniqueness by address + name combination).",
      "invariant": false,
      "invariant_justification": "This is a business policy to prevent accidental duplicates. A business could decide to allow duplicate recipients in edge cases (e.g., multiple deliveries to the same address for different purposes).",
      "testable_assertion": "Adding a Recipient with the same name and address as an existing Recipient on the same Shipment is rejected by default."
    }
  ],

  "acceptance_criteria": [
    {
      "id": "AC-1",
      "given": "A new Shipment is being created",
      "when": "The request includes two or more Recipients with valid data and distinct delivery preferences",
      "then": "The Shipment is created successfully with all Recipients persisted and individually addressable"
    },
    {
      "id": "AC-2",
      "given": "A new Shipment is being created",
      "when": "The request includes zero Recipients",
      "then": "The system rejects the request with a clear validation error"
    },
    {
      "id": "AC-3",
      "given": "An existing single-recipient Shipment created before the migration",
      "when": "It is queried via any existing API or UI",
      "then": "It returns correctly with the Recipient data intact, indistinguishable from pre-migration behavior"
    },
    {
      "id": "AC-4",
      "given": "A multi-recipient Shipment where 2 of 3 Recipients have been delivered",
      "when": "The Shipment status is queried",
      "then": "The status reflects partial completion (not 'delivered'), and per-Recipient statuses are individually queryable"
    },
    {
      "id": "AC-5",
      "given": "A partner API integration consuming shipment data in the v1 format",
      "when": "A multi-recipient Shipment is created",
      "then": "The partner receives data via the existing v1 contract (e.g., one webhook per Recipient, or only the primary Recipient) without breaking. A v2 endpoint is available for partners that opt in."
    },
    {
      "id": "AC-6",
      "given": "A Shipment with multiple Recipients",
      "when": "One Recipient's delivery fails",
      "then": "Only that Recipient's delivery is marked failed. The Shipment continues processing for remaining Recipients. Retry/reroute logic applies per-Recipient."
    },
    {
      "id": "AC-7",
      "given": "The production database with ~2M existing Shipments",
      "when": "The data migration runs",
      "then": "All 2M Shipments are migrated to the new schema with exactly one Recipient each. Migration is reversible. Zero data loss confirmed by row-count and checksum validation."
    }
  ],

  "edge_cases": [
    {
      "scenario": "A Shipment has 50+ Recipients (bulk distribution scenario)",
      "expected_behavior": "System should enforce a reasonable maximum (business-defined cap) to prevent abuse and operational issues. The cap is a policy, not an invariant — it can be adjusted."
    },
    {
      "scenario": "Two Recipients on the same Shipment have the same address but different delivery preferences",
      "expected_behavior": "This is valid — e.g., two people at the same office with different signature requirements. The system must treat them as distinct Recipients."
    },
    {
      "scenario": "A Recipient is removed from a multi-recipient Shipment after the Shipment is in-transit",
      "expected_behavior": "Domain must define whether this is allowed. If goods are already en route, removing a Recipient has physical-world consequences (rerouting, returns). This likely requires a cancellation sub-flow per Recipient, not a simple delete."
    },
    {
      "scenario": "All Recipients on a multi-recipient Shipment fail delivery",
      "expected_behavior": "Shipment status becomes 'failed' (not 'partially_delivered'). Return-to-sender or hold logic applies to the entire Shipment."
    },
    {
      "scenario": "Partner API receives a webhook for a multi-recipient Shipment but only supports single-recipient format",
      "expected_behavior": "Anti-corruption layer must fan-out: either send one webhook per Recipient in v1 format, or send only a designated primary Recipient. Partner must not receive malformed data."
    },
    {
      "scenario": "Billing: is a multi-recipient Shipment billed as one shipment or N shipments?",
      "expected_behavior": "This is a critical business decision that must be explicitly defined before implementation. Billing model affects pricing, invoicing, and revenue recognition. Cannot be assumed."
    },
    {
      "scenario": "Tracking number: does a multi-recipient Shipment have one tracking number or one per Recipient?",
      "expected_behavior": "Depends on physical logistics — if goods travel together then split, a parent tracking number with child numbers per Recipient is likely. Must be defined with operations team."
    }
  ],

  "business_impact": {
    "financial": "Revenue model is directly affected — pricing per Shipment vs per Recipient must be decided. Multi-recipient shipments could increase average order value but complicate invoicing. Migration costs include engineering time, testing, and potential downtime. Partner re-integration may require dedicated support.",
    "operational": "Significant operational complexity increase. Courier dispatch logic must handle multiple stops per Shipment. Route optimization changes. Status tracking becomes per-Recipient. Support teams need training on new model. Reporting and analytics must be updated to handle 1:N relationships without double-counting.",
    "user": "Customers gain flexibility — can send to multiple recipients in one transaction. However, tracking UX becomes more complex (partial delivery states). Notification system must support per-Recipient updates. Confusion risk if status reporting is not clear.",
    "risk": "HIGH. This is a core domain model change affecting the primary aggregate root. Risks include: (1) data migration failure on 2M records, (2) partner API breakage causing delivery failures, (3) inconsistent Shipment status leading to incorrect operational decisions, (4) billing errors during transition, (5) performance degradation from 1:N joins on high-traffic queries.",
    "stakeholders_affected": [
      { "group": "Customers (Senders)", "impact": "New capability to send to multiple recipients. Must understand new tracking/status model." },
      { "group": "Recipients", "impact": "No direct change to their experience if implemented correctly. Risk of confusion if they see statuses for other Recipients." },
      { "group": "Couriers / Drivers", "impact": "Dispatch and routing changes. A single Shipment may now require multiple stops. Delivery confirmation must be per-Recipient." },
      { "group": "External Partners (API consumers)", "impact": "Breaking change to data contract. Requires migration to v2 API or anti-corruption layer. Risk of integration failure if not handled." },
      { "group": "Customer Support", "impact": "Must handle inquiries about partial deliveries, per-Recipient failures, and more complex Shipment states." },
      { "group": "Finance / Billing", "impact": "Pricing model, invoicing, and revenue recognition all affected. Must define billing unit before implementation." },
      { "group": "Operations / Logistics", "impact": "Route planning, warehouse operations, and delivery confirmation workflows all change." },
      { "group": "Data / Analytics", "impact": "All shipment metrics, KPIs, and dashboards must account for 1:N relationship. Historical comparisons need normalization." }
    ]
  },

  "confidence": {
    "level": 45,
    "reasoning": "The spec describes a structural model change but leaves critical business decisions undefined: billing model (per-shipment vs per-recipient), tracking number strategy, Shipment status state machine for partial delivery, partner migration strategy, and whether Recipients are entities with identity or value objects. These gaps make it impossible to define complete, correct acceptance criteria. Multiple stakeholder groups are affected with unresolved concerns.",
    "high_confidence_areas": [
      "At-least-one-Recipient invariant",
      "Backward compatibility requirement for existing data",
      "Partner API must not break silently",
      "Per-Recipient delivery preferences are independent"
    ],
    "low_confidence_areas": [
      "Billing model for multi-recipient Shipments — not specified",
      "Tracking number topology — one per Shipment or one per Recipient",
      "Shipment aggregate status state machine for partial completion",
      "Whether Recipient removal is allowed after Shipment is in-transit",
      "Maximum Recipient count per Shipment",
      "Whether delivery preferences have a defined schema or are free-form"
    ],
    "assumptions": [
      "The 1:N model means multiple Recipients with potentially different addresses, not just multiple contacts at the same address",
      "Existing partner APIs are external and cannot be force-upgraded simultaneously",
      "The migration must be online (zero or near-zero downtime) given 2M production records",
      "Delivery preferences is a new concept being introduced alongside multi-recipient support"
    ]
  },

  "escalations": [
    {
      "type": "ambiguity",
      "description": "Billing model for multi-recipient Shipments is undefined. Is a Shipment with 3 Recipients billed as 1 shipment or 3? This fundamentally changes pricing, invoicing, and revenue recognition.",
      "affected_stakeholders": ["Finance / Billing", "Customers (Senders)", "Product"],
      "options": [
        "Bill per Shipment (flat rate regardless of recipient count)",
        "Bill per Recipient (each recipient adds cost)",
        "Tiered model (base rate + per-additional-recipient fee)"
      ],
      "recommendation": "Must be decided by product and finance before implementation. This affects database schema (billing records) and cannot be easily changed post-launch."
    },
    {
      "type": "ambiguity",
      "description": "Shipment status state machine for partial delivery is undefined. What statuses exist when some Recipients are delivered and others are not? The current status model (likely: created → in-transit → delivered → failed) does not accommodate partial states.",
      "affected_stakeholders": ["Customers (Senders)", "Customer Support", "Operations / Logistics", "Data / Analytics"],
      "options": [
        "Add 'partially_delivered' top-level status",
        "Keep Shipment status as 'in-transit' until ALL Recipients are resolved, track per-Recipient status separately",
        "Decompose into per-Recipient delivery tasks with independent lifecycles"
      ],
      "recommendation": "Option C (per-Recipient delivery tasks) is the most domain-faithful but highest effort. Option B is pragmatic. Needs product decision."
    },
    {
      "type": "ambiguity",
      "description": "Tracking number topology is undefined. Does a multi-recipient Shipment get one tracking number or one per Recipient? This depends on physical logistics — whether goods travel together or separately.",
      "affected_stakeholders": ["Customers (Senders)", "Recipients", "Couriers / Drivers", "External Partners"],
      "options": [
        "One tracking number per Shipment (Recipients share it)",
        "One tracking number per Recipient (each is independently trackable)",
        "Hierarchical: parent tracking number with child numbers per Recipient"
      ],
      "recommendation": "Depends on physical fulfillment model. If goods ship from one origin and split en route, hierarchical is correct. If they ship independently, per-Recipient is correct. Operations team must weigh in."
    },
    {
      "type": "missing_context",
      "description": "The schema and semantics of 'delivery preferences' are not defined. The spec says each Recipient 'can have different delivery preferences' but does not enumerate what preferences exist, whether they are required or optional, or what their valid values are.",
      "affected_stakeholders": ["Product", "Customers (Senders)", "Couriers / Drivers"],
      "options": [
        "Define a fixed enum of preference types (signature required, leave at door, time window, etc.)",
        "Allow free-form key-value preferences",
        "Define a base set with extensibility for future preferences"
      ],
      "recommendation": "Define a bounded set of preference types now. Free-form preferences lead to inconsistency and are unenforceable by couriers."
    },
    {
      "type": "ambiguity",
      "description": "Partner API migration strategy is undefined. With ~2M existing shipments and external partners consuming v1 format, the transition plan must be explicit — how long is v1 supported? Is there a deprecation timeline? Who communicates changes to partners?",
      "affected_stakeholders": ["External Partners (API consumers)", "Product", "Engineering"],
      "options": [
        "Maintain v1 indefinitely with anti-corruption layer",
        "Deprecate v1 with 6-12 month sunset period",
        "Dual-publish: v1 for single-recipient, v2 for multi-recipient"
      ],
      "recommendation": "Dual-publish initially with a defined deprecation timeline for v1. Partners need migration guides and sandbox environments."
    }
  ],

  "rejection_reasons": []
}

